import React, { useEffect, useState } from "react";
import api from "../api";
import KycForm from "./KycForm";

export default function Dashboard({ username, onLogout }) {
  const [loans, setLoans] = useState([]);
  const [loanForm, setLoanForm] = useState({
    principal: "",
    interestRate: "",
    tenureMonths: "",
  });
  const [info, setInfo] = useState("");

  useEffect(() => {
    loadLoans();
  }, [username]);

  const loadLoans = async () => {
    try {
      const res = await api.get("/loan/all", {
        params: { username },
      });
      setLoans(res.data);
    } catch (error) {
      console.error(error);
      setInfo("Error loading loans");
    }
  };

  const requestCheckBook = async () => {
    try {
      const res = await api.post("/checkbook/request", {
        username,
      });
      setInfo(res.data);
    } catch {
      setInfo("Error requesting check book");
    }
  };

  const applyLoan = async (e) => {
    e.preventDefault();

    try {
      const payload = {
        principal: parseFloat(loanForm.principal),
        interestRate: parseFloat(loanForm.interestRate),
        tenureMonths: parseInt(loanForm.tenureMonths, 10),
        username,
      };

      const res = await api.post("/loan/apply", payload);

      setInfo("Loan applied successfully");
      loadLoans();
    } catch {
      setInfo("Error applying for loan");
    }
  };

  const handleLoanChange = (e) => {
    setLoanForm({ ...loanForm, [e.target.name]: e.target.value });
  };

  return (
    <div className="dashboard">
      <h1>Welcome, {username}</h1>

      <button onClick={onLogout}>Logout</button>

      <h2>Chequebook</h2>
      <button onClick={requestCheckBook}>Request Checkbook</button>

      <h2>Apply for Loan</h2>
      <form onSubmit={applyLoan}>
        <input
          name="principal"
          placeholder="Principal"
          onChange={handleLoanChange}
          required
        />
        <input
          name="interestRate"
          placeholder="Interest Rate"
          onChange={handleLoanChange}
          required
        />
        <input
          name="tenureMonths"
          placeholder="Tenure Months"
          onChange={handleLoanChange}
          required
        />
        <button type="submit">Apply</button>
      </form>

      <h3>Your Loans</h3>
      <ul>
        {loans.map((loan) => (
          <li key={loan.id}>
            ₹{loan.principal} - {loan.status}
          </li>
        ))}
        {loans.length === 0 && <li>No loans yet.</li>}
      </ul>

      {info && <p>{info}</p>}

      <KycForm username={username} />
    </div>
  );
}
